<div class="page-title-row"><div><span class="text-muted">Customer profile</span><h1><?=e($customer['display_name'])?></h1><p class="text-muted mb-0"><?=e($customer['contact_name'])?> · <?=e($customer['phone'])?> · <?=e($customer['email'])?></p></div><div><a href="/portal/estimates/create?customer_id=<?=$customer['id']?>" class="btn btn-primary">New Estimate</a> <a href="/portal/customers/<?=$customer['id']?>/edit" class="btn btn-outline-secondary">Edit</a></div></div>
<div class="row g-4"><div class="col-lg-4"><div class="portal-card p-4 mb-4"><div class="d-flex justify-content-between align-items-center"><h2 class="h5">Properties</h2><a class="btn btn-sm btn-outline-primary" href="/portal/customers/<?=$customer['id']?>/properties/create">Add Property</a></div><?php foreach($properties as $p):?><div class="border rounded p-3 mt-3"><strong><?=e($p['label'])?></strong><br><?=e($p['address1'])?><br><?=e($p['city'].', '.$p['state'].' '.$p['postal_code'])?></div><?php endforeach?></div><div class="portal-card p-4"><h2 class="h5">Notes</h2><p class="mb-0"><?=nl2br(e($customer['notes']))?></p></div></div>
<div class="col-lg-8"><div class="portal-card"><ul class="nav nav-tabs px-3 pt-3" role="tablist"><li class="nav-item"><button class="nav-link active" data-bs-toggle="tab" data-bs-target="#timeline">Timeline</button></li><li class="nav-item"><button class="nav-link" data-bs-toggle="tab" data-bs-target="#estimates">Estimates</button></li><li class="nav-item"><button class="nav-link" data-bs-toggle="tab" data-bs-target="#jobs">Jobs</button></li><li class="nav-item"><button class="nav-link" data-bs-toggle="tab" data-bs-target="#invoices">Invoices</button></li></ul><div class="tab-content p-4"><div class="tab-pane fade show active" id="timeline"><div class="customer-timeline"><?php foreach($timeline as $event):?><article class="timeline-event"><div class="timeline-icon"><i class="fa-solid <?=e($event['icon'])?>"></i></div><div><div class="d-flex justify-content-between gap-3"><strong><?=e(ucfirst($event['type']))?>: <?=e($event['ref'])?></strong><time><?=e(date('M j, Y g:i A',strtotime($event['occurred_at'])))?></time></div><p class="text-muted mb-1"><?=e((string)$event['status'])?><?php if(is_numeric($event['total'])):?> · <?=money((float)$event['total'])?><?php elseif($event['total']):?> · <?=e((string)$event['total'])?><?php endif?></p><a href="<?=e($event['url'])?>">View details</a></div></article><?php endforeach;if(!$timeline):?><p class="text-muted">No recorded activity yet.</p><?php endif?></div></div><div class="tab-pane fade" id="estimates"><div class="table-responsive"><table class="table"><tbody><?php foreach($estimates as $r):?><tr><td><a href="/portal/estimates/<?=$r['id']?>"><?=e($r['estimate_number'])?></a></td><td><?=e($r['status'])?></td><td><?=money($r['total'])?></td></tr><?php endforeach?></tbody></table></div></div><div class="tab-pane fade" id="jobs"><table class="table"><?php foreach($jobs as $r):?><tr><td><a href="/portal/jobs/<?=$r['id']?>"><?=e($r['job_number'])?></a></td><td><?=e($r['status'])?></td><td><?=e($r['scheduled_start'])?></td></tr><?php endforeach?></table></div><div class="tab-pane fade" id="invoices"><table class="table"><?php foreach($invoices as $r):?><tr><td><a href="/portal/invoices/<?=$r['id']?>"><?=e($r['invoice_number'])?></a></td><td><?=e($r['status'])?></td><td><?=money($r['balance_due'])?></td></tr><?php endforeach?></table></div></div></div></div></div>
